output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT(SUM(?raceCount) AS ?total) WHERE {
  {
    SELECT(COUNT(?race) AS ?raceCount) WHERE {
      ?season wdt:P31 wd:Q32351 .
      ?season wdt:P1346 wd:Q9671 .
      ?season wdt:P585 ?year .
      ?race wdt:P361 ?season .
    }
    GROUP BY ?season ?year
    ORDER BY ?year
    LIMIT 1
  } UNION {
    SELECT(COUNT(?race) AS ?raceCount) WHERE {
      ?season wdt:P31 wd:Q32351 .
      ?season wdt:P1346 wd:Q9671 .
      ?season wdt:P585 ?year .
      ?race wdt:P361 ?season .
    }
    GROUP BY ?season ?year
    ORDER BY DESC(?year)
    LIMIT 1
  }
}

